/*\n  # Optimize High Sequential Scan Tables\n\n  1. Critical Performance Issues Identified\n    - **user_roles**: 1.16M sequential scans (78% seq scan rate)\n      - Missing index on role column for role-based queries\n      - Heavily used in RLS policies (329 policies with EXISTS subqueries)\n    \n    - **regions**: 3.5K sequential scans (52% seq scan rate)\n      - Missing composite index for active region lookups\n    \n    - **eats_zones**: 4.5K sequential scans (83% seq scan rate)\n      - Missing index on is_active for active zone filtering\n    \n    - **flight_funnel_events**: 100% sequential scan rate\n      - Missing index on user_id for user activity tracking\n    \n    - **driver_location_events**: 100% sequential scan rate\n      - Missing indexes on common filter columns\n\n  2. New Indexes\n    - Single-column indexes for frequently filtered columns\n    - Composite indexes for common query patterns\n    - Partial indexes for active/enabled filtering\n\n  3. Expected Impact\n    - Reduce 1M+ sequential scans on user_roles\n    - Speed up RLS policy evaluation across 329 policies\n    - Improve region and zone lookup performance\n    - Optimize funnel tracking and location queries\n*/\n\n-- user_roles optimization (CRITICAL - used in 329 RLS policies)\nCREATE INDEX IF NOT EXISTS idx_user_roles_role ON public.user_roles(role);
\nCREATE INDEX IF NOT EXISTS idx_user_roles_user_role_composite ON public.user_roles(user_id, role);
\n\n-- regions optimization\nCREATE INDEX IF NOT EXISTS idx_regions_active_city_state ON public.regions(is_active, city, state) WHERE is_active = true;
\n\n-- eats_zones optimization\nCREATE INDEX IF NOT EXISTS idx_eats_zones_active ON public.eats_zones(is_active);
\nCREATE INDEX IF NOT EXISTS idx_eats_zones_city_active ON public.eats_zones(city_id, is_active) WHERE is_active = true;
\n\n-- flight_funnel_events optimization\nCREATE INDEX IF NOT EXISTS idx_flight_funnel_user_id ON public.flight_funnel_events(user_id) WHERE user_id IS NOT NULL;
\nCREATE INDEX IF NOT EXISTS idx_flight_funnel_user_event ON public.flight_funnel_events(user_id, event_type, created_at DESC) WHERE user_id IS NOT NULL;
\n\n-- driver_location_events optimization (100% seq scan)\nCREATE INDEX IF NOT EXISTS idx_driver_location_events_recorded_at ON public.driver_location_events(recorded_at DESC);
\nCREATE INDEX IF NOT EXISTS idx_driver_location_events_driver_state ON public.driver_location_events(driver_state);
\nCREATE INDEX IF NOT EXISTS idx_driver_location_events_state_time ON public.driver_location_events(driver_state, recorded_at DESC);
\n\n-- Additional high-impact optimizations\nCREATE INDEX IF NOT EXISTS idx_security_events_user_type ON public.security_events(user_id, event_type, created_at DESC) WHERE user_id IS NOT NULL;
\nCREATE INDEX IF NOT EXISTS idx_security_events_severity ON public.security_events(severity, created_at DESC);
\nCREATE INDEX IF NOT EXISTS idx_driver_documents_status_expires ON public.driver_documents(status, expires_at) WHERE expires_at IS NOT NULL;
;
